//nolint:revive
package common

import (
	"encoding/base64"
	"path/filepath"
	"strings"
)

var (
	// Description holds the client cli description.
	Description = "Client used to connect and manage the server ahd the connection to the agent." +
		"\nThe client will try to load configuration from " + filepath.Join("$HOME", ".config", strings.ToLower(AppName)+".yaml") +
		"\nAs well as " + strings.ToLower(AppName) + ".yaml" + " on the current directory."
	b64banner = ``
)

// AppName the client application name.
const AppName = "tealc"

// GetBanner returns the banner used when the help is called by users.
func GetBanner() string {
	res, err := base64.StdEncoding.DecodeString(b64banner)
	if err != nil {
		return ""
	}

	return string(res)
}
